s($,"btR","b8h",()=>A.iA(new A.aQo(),B.dp,"You built a road! Your stones form an unbroken path from one edge to the opposite edge. That's how you win at Tak.",B.VY,B.Q5,null,null,"tutorial_1","Place a stone to complete the road.",1,B.dh,null,B.dT,"Complete a road from top to bottom.","Building a Road",B.bh))
s($,"btS","b8i",()=>A.iA(new A.aQp(),B.dp,"Your wall blocks their road! Walls are powerful blockers, but remember they can't be part of your road. Use them strategically.",B.Yd,B.Q3,null,null,"tutorial_2","Select the wall piece type, then place it to block Black.",2,A.b(["tutorial_1"],t.s),null,B.o6,"Use a wall to block an opponent's road.","Standing Stones (Walls)",B.bh))
s($,"btT","b8j",()=>A.iA(new A.aQq(),B.dp,"The wall is now flat \u2014 and your road is complete! The Capstone is essential for breaking through defenses.",B.WT,B.Q0,null,null,"tutorial_3","Move the Capstone onto the wall to flatten it.",3,A.b(["tutorial_2"],t.s),null,B.dT,"Use the Capstone to flatten a wall.","The Capstone",B.bh))
s($,"btU","b8k",()=>A.iA(new A.aQr(),B.dp,"Pieces can move onto empty cells or onto other pieces (creating stacks). Moving lets you reposition without using new pieces from your supply.",B.Y0,B.vb,null,null,"tutorial_4","Move your stone onto the adjacent black piece.",4,A.b(["tutorial_3"],t.s),null,B.wh,"Learn to move pieces on the board.","Moving a Single Piece",B.bh))
s($,"btV","b8l",()=>A.iA(new A.aQs(),B.dp,"The whole stack moved together! Controlling your opponent's pieces in stacks is a powerful tactic. Only the top piece determines the stack's color for roads.",B.W2,B.vb,null,null,"tutorial_5","Move the stack to demonstrate control.",5,A.b(["tutorial_4"],t.s),null,B.o6,"Understand stack control.","Stacks and Control",B.bh))
s($,"btW","b8m",()=>A.iA(new A.aQt(),B.dp,"Excellent! You can only carry up to the board size (5 on a 5\xd75 board), even from taller stacks. Use this to spread influence across the board!",B.YA,B.Q2,null,null,"tutorial_6","Spread the stack across the board.",6,A.b(["tutorial_5"],t.s),null,B.o6,"Learn about carry limits and dropping pieces.","Stack Movement & Carry Limit",B.bh))
s($,"btX","b8n",()=>A.iA(new A.aQu(),B.dp,"The opening rule is easy to forget! Some players place the opponent's piece in a corner (giving them little value), others place it centrally (creating interesting positions).",B.X7,B.va,null,null,"tutorial_7","Place a Black flat stone (your opponent's color).",7,A.b(["tutorial_6"],t.s),null,B.wh,"Learn the special first-turn rule.","The Opening Rule",B.bh))
s($,"btY","b8o",()=>A.iA(new A.aQv(),B.dp,"You won by flat count! You had more flat stones showing on top. Walls block roads but hurt your flat count \u2014 use them wisely.",B.VT,B.Q1,null,null,"tutorial_8","Place your last stone to fill the board and win!",8,A.b(["tutorial_7"],t.s),null,B.dT,"Learn the alternative win condition.","Winning by Flat Count",B.bh))
s($,"btZ","b8p",()=>A.iA(new A.aQw(),B.dp,"When pieces run low, every placement matters. Sometimes it's better to move existing pieces rather than place new ones. Watch your supply \u2014 and your opponent's!",B.Vp,B.va,null,null,"tutorial_9","Place your last piece to end the game.",9,A.b(["tutorial_8"],t.s),null,B.dT,"Manage your limited piece supply.","Running Out of Pieces",B.bh))
