s($,"btl","b7U",()=>A.iA(new A.aQb(),B.pw,"Spreading over enemy pieces converts them to your road. A powerful finishing move!",B.XH,B.Q4,null,null,"puzzle_7","Win in 1 move. Spread over the enemy pieces to complete your road!",2,A.b(["puzzle_6"],t.s),B.pm,B.dT,"Spread your stack to complete your road!","The Spread",B.bY))
s($,"btm","b7V",()=>A.iA(new A.aQc(),B.pw,"The Capstone flattens walls that would stop any other piece. Master this technique!",B.UL,B.vc,null,null,"puzzle_9","Win in 1 move. Flatten the wall to complete your road!",3,A.b(["puzzle_7"],t.s),B.pm,B.dT,"Use your Capstone to flatten and win!","Capstone Tactics",B.bY))
