s($,"bti","b7R",()=>A.iA(new A.aQ8(),B.px,"Three precise moves! The setup placement was crucial \u2014 moving the Capstone first would have failed. Patience and planning win in Tak.",B.YH,B.v9,B.n9,"Don't move the Capstone yet. Create a threat on Column 3 first...","puzzle_11","Win in 3 moves. Every move must be precise!",2,A.b(["puzzle_10"],t.s),B.pn,B.vU,"A three-move forced win \u2014 if you find the right sequence!","The Crucible",B.bY))
